// V-register transport via shared scratch RAM. The vsim Debug Module
// abstract-command space does not allocate slots for v0..v31 (RISC-V Debug
// Spec leaves V to optional Program Buffer or implementation-specific
// extensions), and the AX45MPV CPU wrapper does not export a DPI probe for
// the V regfile. As a stop-gap that keeps Phase 5 (DPI / PB) deferred while
// still letting C-level RVV fixtures round-trip:
//
//   - On resume from QEMU 1, vsim copies state.vreg[] into a fixed scratch
//     region of guest RAM (kVScratchGpa). The fixture's vsim-phase prologue
//     issues `vle8.v vN, (t0)` against that region to repopulate v0..v31.
//   - Before the vsim->QEMU2 drain trigger, the fixture issues `vse8.v vN,
//     (t0)` to write the (possibly mutated) regfile back to the same region.
//     vsim's StateDrain side reads the scratch bytes into state.vreg[] so
//     qemu_handback can ship them to QEMU 2 via the existing gdbstub P
//     packets.
//
// The contract is fixture-aware: any program that wants V state preserved
// across the vsim boundary must perform the load/store at the boundaries.
// rt_c_v_regs.c demonstrates the pattern. Phase 5 will replace this with a
// transparent mechanism (PB or DPI) so benchmark binaries don't need to be
// modified.
//
// Pure logic: no SystemC, no DMI bus. Easy to unit-test.

#pragma once

#include "hybrid/state_abi.h"

#include <cstddef>
#include <cstdint>
#include <cstring>
#include <span>
#include <stdexcept>

namespace hybrid
{

// Reserved scratch slot inside the shared mmap. Sits well above the C
// runtime's _stack (rt_c.ld places it at RAM_BASE + 0x700000), giving the
// stack ~9 MiB of headroom before colliding with this 2 KiB region. On
// `-M andes_ae350` RAM is at 0x00000000 and the GPA is 0x00FF0000; on
// `-M virt` it would be 0x80FF0000. The chosen address is RAM_BASE +
// 0xFF0000, an offset that has to match the `li t0, ...` constant in the
// fixture's runtime/v_regfile_xfer.c.
inline constexpr uint64_t kVScratchGpa = 0x00FF0000ull;

// Total scratch bytes needed: 32 V regs × HYBRID_VLEN_BYTES_MAX. Sized to
// the maximum supported VLEN; the actual per-reg byte count is `vlenb`.
inline constexpr std::size_t kVScratchBytes =
  static_cast<std::size_t>(32) * HYBRID_VLEN_BYTES_MAX;

namespace detail
{

// Translate scratch GPA into a byte offset inside a RAM span whose first
// byte sits at `ram_base`. Throws if the scratch region falls outside the
// supplied span (i.e. the caller passed a too-small RAM mapping).
inline auto scratch_offset(std::size_t ram_size, uint64_t ram_base)
  -> std::size_t
{
  if (kVScratchGpa < ram_base)
    throw std::runtime_error(
      "v_regfile_xfer: scratch GPA below RAM base");
  const auto off = static_cast<std::size_t>(kVScratchGpa - ram_base);
  if (off + kVScratchBytes > ram_size)
    throw std::runtime_error(
      "v_regfile_xfer: scratch region exceeds RAM span");
  return off;
}

}  // namespace detail

// Copy state.vreg[] into ram[scratch_offset .. scratch_offset+kVScratchBytes].
// Called just before vsim resumes the hart so the fixture can vle8.v from
// scratch and pick up QEMU 1's V values.
inline void stage_v_to_scratch(const hybrid_state_v1& state,
                               std::span<uint8_t> ram,
                               uint64_t ram_base)
{
  const auto off = detail::scratch_offset(ram.size(), ram_base);
  std::memcpy(ram.data() + off, state.vreg, kVScratchBytes);
}

// Copy ram[scratch_offset .. +kVScratchBytes] into state.vreg[]. Called
// inside the vsim drain path after the fixture's prologue vse8.v has
// settled the (possibly mutated) regfile bytes into RAM.
inline void read_v_from_scratch(hybrid_state_v1& state,
                                std::span<const uint8_t> ram,
                                uint64_t ram_base)
{
  const auto off = detail::scratch_offset(ram.size(), ram_base);
  std::memcpy(state.vreg, ram.data() + off, kVScratchBytes);
}

}  // namespace hybrid

/* Tier-2 C-level fixture: 1D 3-tap FIR convolution split across all three
 * handoff phases, with the V regfile as the carrier of state between
 * QEMU 1 <-> vsim and vsim <-> QEMU 2.
 *
 * Workload
 *   y[i] = x[i-1] + 2 * x[i] + x[i+1]     (zero-padded at the edges)
 *   x[i] = i + 1                          (i in 0..15)
 *
 * Phase split (mirrors a realistic hybrid-sim use case: fast functional
 * setup / cycle-accurate vector kernel / fast functional verify):
 *
 *   QEMU 1   generate x via vid + 1
 *   vsim     apply the FIR kernel: vslide1up / vslide1down + vadd
 *   QEMU 2   vse32 y, scalar verify against the lane-wise closed form
 *
 * V regfile transport
 *   x rides QEMU 1 -> vsim in its compiler-picked V register.
 *   y rides vsim   -> QEMU 2 in its compiler-picked V register.
 *
 *   The fixture never names a physical V register. The runtime helpers
 *   v_regfile_reload_all / v_regfile_dump_all (see v_regfile_xfer.h)
 *   save/restore the full 32-V-reg regfile bit-identically through
 *   V_SCRATCH at each boundary. Because every V reg's contents survive
 *   the round trip, the compiler's per-variable tracking ("x lives in
 *   v_compiler_choice") stays valid across enter_vsim and exit_vsim and
 *   the body of main() can be written in pure RVV intrinsics.
 *
 * Compiler hazard guard
 *   The empty asm volatile blocks with "vr" inputs ("force-live") pin
 *   the intrinsic-typed values in V regs at exact source points right
 *   before the boundary. Without them, the compiler may elide x's
 *   compute from phase 1 (treating it as dead before enter_vsim and
 *   re-emittable later) and the plugin would drain a wrong V regfile.
 *
 * VLEN contract: VLEN=512, e32 m1 -> 16 lanes per V reg. N=16.
 *
 * Phase-2 rule: no syscalls between enter_vsim and exit_vsim (vsim does
 * not implement semihosting).
 */
#include "runtime/rt_c_helpers.h"
#include "runtime/v_regfile_xfer.h"

#include <riscv_vector.h>
#include <stdint.h>
#include <stdio.h>

#define N 16

int main(void)
{
  const size_t vl = __riscv_vsetvl_e32m1((size_t) N);

  /* Phase 1 (QEMU 1): x = [1, 2, 3, ..., N] via vid + 1. */
  const vuint32m1_t vid_u = __riscv_vid_v_u32m1(vl);
  const vint32m1_t  x     = __riscv_vadd_vx_i32m1(
        __riscv_vreinterpret_v_u32m1_i32m1(vid_u), 1, vl);

  asm volatile("" : : "vr"(x));  /* force x live before drain */

  enter_vsim();
  v_regfile_reload_all();

  /* Phase 2 (vsim): 3-tap FIR convolution
   *   x_left[i]  = (i == 0)     ? 0 : x[i - 1]   (vslide1up)
   *   x_right[i] = (i == N - 1) ? 0 : x[i + 1]   (vslide1down)
   *   y[i]       = x_left[i] + 2 * x[i] + x_right[i] */
  const vint32m1_t x_left  = __riscv_vslide1up_vx_i32m1(x, 0, vl);
  const vint32m1_t x_right = __riscv_vslide1down_vx_i32m1(x, 0, vl);
  const vint32m1_t two_x   = __riscv_vsll_vx_i32m1(x, 1, vl);          /* 2*x */
  const vint32m1_t partial = __riscv_vadd_vv_i32m1(x_left, two_x, vl); /* x_left + 2x */
  const vint32m1_t y       = __riscv_vadd_vv_i32m1(partial, x_right, vl);

  asm volatile("" : : "vr"(y));  /* force y live before drain */

  v_regfile_dump_all();
  exit_vsim();

  /* Phase 3 (QEMU 2): store y and verify. */
  int32_t out[N];
  __riscv_vse32_v_i32m1(out, y, vl);

  for (int i = 0; i < N; i++) {
    const int32_t x_im1 = (i == 0)     ? 0 : i;        /* x[i-1] zero-padded */
    const int32_t x_i   = i + 1;                        /* x[i] */
    const int32_t x_ip1 = (i == N - 1) ? 0 : (i + 2);   /* x[i+1] zero-padded */
    const int32_t expected = x_im1 + 2 * x_i + x_ip1;
    if (out[i] != expected) {
      printf("rt_c_v_regs: FAIL i=%d got=%d expected=%d\n", i, (int) out[i],
             (int) expected);
      fflush(stdout);
      return 1;
    }
  }
  printf("rt_c_v_regs: PASS\n");
  fflush(stdout);
  return 0;
}
